239	  private async insertLiveStreams(data: Stream[], time: Date): Promise<void> {
240	    if (data.length === 0) return Promise.resolve();
241	    // insert live
242	    const insert = buildMultiInsert<Stream>(
243	      'INSERT INTO user_online (user_id,stream_id,last_update) VALUES ',
244	      '$1,$2,$3',
245	      data,
246	      (d: Stream) => [d.user_id, d.id, time]
247	    );
248	    insert.text +=
249	      ' ON CONFLICT (user_id,stream_id) DO UPDATE SET last_update=EXCLUDED.last_update';
250	
251	    return this.query(insert);
252	  }
253	
254	  private async insertProbes(data: Stream[], time: Date): Promise<void> {
255	    if (data.length === 0) return Promise.resolve();
256	    // insert into probe
257	    const insert = buildMultiInsert<Stream>(
258	      'INSERT INTO probe (stream_id,user_id,viewers,time) VALUES ',
259	      '$1,$2,$3,$4',
260	      data,
261	      (d: Stream) => [d.id, d.user_id, d.viewer_count, time]
262	    );
263	    insert.text += ' ON CONFLICT (stream_id, user_id,time) DO NOTHING';
264	
265	    return this.query(insert);
266	  }
