268	  private async insertUpdateStreams(data: Stream[], time: Date): Promise<void> {
269	    if (data.length === 0) return Promise.resolve();
270	    // insert into stream
271	    const insert = buildMultiInsert<Stream>(
272	      'INSERT INTO stream (stream_id,user_id,title,tags,game_id,started_at,updated_at) VALUES ',
273	      '$1,$2,$3,$4,$5,$6,$7',
274	      data,
275	      (d: Stream) => [
276	        d.id,
277	        d.user_id,
278	        d.title,
279	        d.tags,
280	        this.assureGameId(d.game_id),
281	        d.started_at,
282	        time,
283	      ]
284	    );
285	    insert.text +=
286	      ' ON CONFLICT (stream_id) DO UPDATE SET title = EXCLUDED.title, tags = EXCLUDED.tags, game_id = EXCLUDED.game_id, ended_at = null, updated_at = EXCLUDED.updated_at';
287	
288	    return this.query(insert);
289	  }
