317	  private async insertStreamsTags(data: Stream[], time: Date): Promise<void> {
318	    if (data.length === 0) return Promise.resolve();
319	    const tags: StreamIdTag[] = [];
320	    data.forEach((d: Stream) => {
321	      if (!d.tags) return;
322	      tags.push({
323	        stream_id: d.id,
324	        tag: d.tags,
325	      });
326	    });
327	    if (tags.length === 0) return Promise.resolve();
328	    const insert = buildMultiInsert<StreamIdTag>(
329	      'INSERT INTO stream_tags (stream_id,tag,time) VALUES ',
330	      '$1,$2,$3',
331	      tags,
332	      (d: StreamIdTag) => [d.stream_id, d.tag, time]
333	    );
334	    insert.text += ' ON CONFLICT (stream_id, tag, time) DO NOTHING';
335	
336	    return this.query(insert);
337	  }
338	
339	  private async splitNewAndOld(data: Array<Stream>): Promise<Split> {
340	    // map of stream ids
341	    const ids = data.map((d) => d.id);
342	    const params = buildInList(ids);
343	    const query = await this.pool.query<DBStream>({
344	      text:
345	        'SELECT * FROM stream WHERE stream_id IN (' + params.join(',') + ')',
346	      values: ids,
347	    });
348	    const oldHash: { [id: string]: DBStream } = {};
349	    for (let i = 0; i < query.rows.length; ++i) {
350	      oldHash[query.rows[i].stream_id] = query.rows[i];
351	    }
352	    const result: Split = {
353	      old: {
354	        ids: [],
355	        data: [],
356	      },
357	      new: {
358	        ids: [],
359	        data: [],
360	      },
361	      query: oldHash,
362	    };
363	    for (let i = 0; i < data.length; ++i) {
364	      const d = data[i];
365	      if (oldHash[d.id]) {
366	        result.old.data.push(d);
367	        result.old.ids.push(d.id);
368	      } else {
369	        result.new.data.push(d);
370	        result.new.ids.push(d.id);
371	      }
372	    }
373	
374	    return result;
375	  }
376	
377	  private changedStreams(split: Split): Changed {
378	    const result: Changed = {
379	      title: [],
380	      game: [],
381	      tags: [],
382	    };
383	
384	    for (let i = 0; i < split.old.data.length; ++i) {
385	      const d = split.old.data[i];
386	      if (d.title !== split.query[d.id].title) {
387	        result.title.push(d);
388	      }
389	      if (d.game_id !== split.query[d.id].game_id) {
390	        result.game.push(d);
391	      }
392	      const dbtag = split.query[d.id].tags;
393	      if ((d.tags ? d.tags.join(',') : '') !== (dbtag ? dbtag.join(',') : '')) {
394	        result.tags.push(d);
395	      }
396	    }
397	
398	    return result;
399	  }
400	}
