1	import {
2	  KafkaConfig,
3	  TwitchConfig,
4	  PostgresConfig,
5	  KafkaConfigOpt,
6	  defaultValues,
7	  TwitchConfigOpt,
8	  PostgresConfigOpt,
9	  FileConfig,
10	  FileConfigOpt,
11	  LogConfig,
12	  LogConfigOpt,
13	} from '@twitch-stats/config';
14	import { init, StreamsMessage } from '@twitch-stats/twitch';
15	import { initPostgres } from '@twitch-stats/database';
16	import type { Pool } from 'pg';
17	import pino, { Logger } from 'pino';
18	import { Kafka, Consumer, Producer } from 'kafkajs';
19	import { ArgumentConfig, parse } from 'ts-command-line-args';
20	import Processing from './processing.js';
21	
22	interface TopicConfig {
23	  topic: string;
24	  streamIdTopic: string;
25	}
26	
27	const TopicConfigOpt: ArgumentConfig<TopicConfig> = {
28	  topic: { type: String, defaultValue: defaultValues.streamsTopic },
29	  streamIdTopic: { type: String, defaultValue: defaultValues.streamsIdTopic },
30	};
31	
32	interface Config
33	  extends KafkaConfig,
34	    TwitchConfig,
35	    PostgresConfig,
36	    FileConfig,
37	    LogConfig,
38	    TopicConfig {}
39	
40	const config: Config = parse<Config>(
41	  {
42	    ...KafkaConfigOpt,
43	    ...TwitchConfigOpt,
44	    ...TopicConfigOpt,
45	    ...PostgresConfigOpt,
46	    ...FileConfigOpt,
47	    ...LogConfigOpt,
48	  },
49	  {
50	    loadFromFileArg: 'config',
51	  }
52	);
53	
54	const logger: Logger = pino({ level: config.logLevel }).child({
55	  module: 'streams-process',
56	});
57	await init(config);
58	
59	const pool: Pool = await initPostgres(config);
60	
61	const kafka: Kafka = new Kafka({
62	  clientId: config.kafkaClientId,
63	  brokers: config.kafkaBroker,
64	});
65	
66	const consumer: Consumer = kafka.consumer({ groupId: 'stream-process' });
67	await consumer.connect();
68	await consumer.subscribe({ topic: config.topic, fromBeginning: true });
69	const producer: Producer = kafka.producer();
70	await producer.connect();
71	const processing: Processing = new Processing(
72	  logger,
73	  pool,
74	  producer,
75	  config.streamIdTopic
76	);
77	
78	await consumer.run({
79	  eachMessage: async ({ message }) => {
80	    try {
81	      logger.trace({ message }, 'message received');
82	      if (!message.value) {
83	        logger.error({ message }, 'no message value');
84	        return;
85	      }
86	      if (!message.timestamp) {
87	        logger.error({ message }, 'message has no timestamp');
88	        return;
89	      }
90	      const d = new Date(parseInt(message.timestamp));
91	      const msg = JSON.parse(message.value.toString()) as StreamsMessage;
92	
93	      await processing.processStreams(d, msg.streams);
94	      if (msg.endConfig) {
95	        await processing.processEnd(msg.endConfig);
96	      }
97	
98	      logger.flush();
99	    } catch (e) {
100	      logger.error({ error: e }, 'error in eachMessage');
101	      console.log(e);
102	      logger.flush();
103	      process.exit();
104	    }
105	  },
106	});
