1	export function buildInList(
2	  values: Array<string>,
3	  startIdx?: number
4	): Array<string> {
5	  startIdx = startIdx ? startIdx : 1;
6	  const result: Array<string> = [];
7	  for (let i = 0; i < values.length; ++i) {
8	    result.push('$' + (startIdx + i));
9	  }
10	  return result;
11	}
12	
13	/* eslint-disable @typescript-eslint/no-explicit-any */
14	
15	export interface Query {
16	  text: string;
17	  values: Array<any>;
18	}
19	
20	export function buildMultiInsert<T>(
21	  stmt: string,
22	  template: string,
23	  data: Array<any>,
24	  mapping: (data: T) => Array<any>
25	): Query {
26	  // split the template
27	  const templateParts = template.split(/\$\d+/);
28	  // need at least subcount columns in a row
29	  const subcount = templateParts.length - 1;
30	
31	  const params = [];
32	  const values = [];
33	  for (let i = 0; i < data.length; ++i) {
34	    let row = data[i];
35	    if (mapping) {
36	      try {
37	        row = mapping(data[i]);
38	      } catch (e) {
39	        throw new Error(`unable to map: ${data[i]}`);
40	      }
41	    }
42	    if (row.length < subcount) {
43	      throw new Error('not enough parameters, need ' + subcount);
44	    }
45	
46	    let chunk = templateParts[0];
47	    for (let j = 0; j < subcount; ++j) {
48	      values.push(row[j]);
49	      chunk += '$' + values.length + templateParts[j + 1];
50	    }
51	    params.push('(' + chunk + ')');
52	  }
53	
54	  return {
55	    text: stmt + params.join(', '),
56	    values,
57	  };
58	}
