-- Pre-migration schema for local testing: the tables the pipeline writes,
-- as they exist in production BEFORE the partitioning migration runs.
-- (Production's schema is the source of truth; this is only for a fresh
-- local database so the dbmate migrations have something to convert.)

CREATE TABLE probe (
  stream_id bigint NOT NULL,
  user_id   bigint NOT NULL,
  viewers   integer NOT NULL,
  "time"    timestamptz(6) NOT NULL,
  PRIMARY KEY (stream_id, user_id, "time")
);

CREATE TABLE stream (
  stream_id  bigint PRIMARY KEY,
  user_id    bigint NOT NULL,
  title      text NOT NULL,
  tags       text[],
  game_id    bigint NOT NULL,
  started_at timestamptz(6) NOT NULL,
  ended_at   timestamptz(6),
  updated_at timestamptz(6)
);
CREATE INDEX ON stream (ended_at);
CREATE INDEX ON stream (started_at);
CREATE INDEX ON stream (updated_at);
CREATE INDEX ON stream (user_id);

CREATE TABLE stream_game (
  stream_id bigint NOT NULL,
  game_id   bigint NOT NULL,
  "time"    timestamptz(6) NOT NULL,
  PRIMARY KEY (stream_id, game_id, "time")
);

CREATE TABLE stream_tags (
  stream_id bigint NOT NULL,
  tag       text[] NOT NULL,
  "time"    timestamptz(6) NOT NULL,
  PRIMARY KEY (stream_id, tag, "time")
);

CREATE TABLE stream_title (
  stream_id bigint NOT NULL,
  title     text NOT NULL,
  "time"    timestamptz(6) NOT NULL,
  PRIMARY KEY (stream_id, title, "time")
);

CREATE TABLE user_online (
  user_id     bigint NOT NULL,
  stream_id   bigint NOT NULL,
  last_update timestamptz(6) NOT NULL,
  PRIMARY KEY (stream_id, user_id)
);
CREATE INDEX ON user_online (last_update);

// Produce fake crawl runs into the streams topic:
//   run1 (t-20m): alice, bob, carol live
//   run2 (t-10m): alice changes title+game, viewers move
//   run3 (t-0):   carol gone -> ended
//   run4 (t+10s): bob gone   -> ended
// Leaves alice live; bob and carol should end up in the archive.
import { Kafka } from 'kafkajs';

const broker = process.env.KAFKA_BROKER ?? 'localhost:19000';
const topic = 'twitch-stats-streams';

const kafka = new Kafka({ clientId: 'seed', brokers: [broker] });
const producer = kafka.producer();
await producer.connect();

const now = Date.now();
const min = 60 * 1000;

function stream(id, user_id, user_name, title, game_id, viewer_count, tags) {
  return {
    id,
    user_id,
    user_name,
    game_id,
    game_name: 'game-' + game_id,
    type: 'live',
    title,
    viewer_count,
    started_at: new Date(now - 25 * min).toISOString(),
    language: 'en',
    thumbnail_url: '',
    tags,
  };
}

async function run(time, streams, endConfig) {
  if (streams.length > 0) {
    await producer.send({
      topic,
      messages: [
        {
          key: 'stream',
          value: JSON.stringify({ streams }),
          timestamp: String(time),
        },
      ],
    });
  }
  await producer.send({
    topic,
    messages: [
      {
        key: 'stream',
        value: JSON.stringify({ streams: [], endConfig }),
        timestamp: String(time),
      },
    ],
  });
}

const alice = () => stream('1001', '101', 'alice', 'building stuff', '509658', 10, ['en', 'dev']);
const bob = () => stream('1002', '102', 'bob', 'speedrun', '33214', 50, ['en']);
const carol = () => stream('1003', '103', 'carol', 'chatting', '509658', 100, ['en', 'chat']);

const t1 = now - 20 * min;
await run(t1, [alice(), bob(), carol()], {
  updateStartTime: new Date(t1 - 1000).toISOString(),
  update: true,
});

const t2 = now - 10 * min;
const alice2 = alice();
alice2.title = 'now: gamedev';
alice2.game_id = '33214';
alice2.viewer_count = 25;
const bob2 = bob();
bob2.viewer_count = 60;
const carol2 = carol();
carol2.viewer_count = 80;
await run(t2, [alice2, bob2, carol2], {
  updateStartTime: new Date(t2 - 1000).toISOString(),
  update: true,
});

const t3 = now;
const alice3 = alice2;
alice3.viewer_count = 30;
const bob3 = bob2;
bob3.viewer_count = 55;
await run(t3, [alice3, bob3], {
  updateStartTime: new Date(t3 - 1000).toISOString(),
  update: true,
});

const t4 = now + 10 * 1000;
await run(t4, [alice3], {
  updateStartTime: new Date(t4 - 1000).toISOString(),
  update: true,
});

console.log('seeded 4 crawl runs');
await producer.disconnect();

// Verify the archive after seed + streams-process + streams-archive ran:
// - archive_stream/stream_summary rows exist
// - each doc is readable from MinIO with a single range GET
// - archived streams are gone from the hot store
import pg from 'pg';
import zlib from 'node:zlib';
import { S3Client, GetObjectCommand } from '@aws-sdk/client-s3';

const pool = new pg.Pool({
  host: 'localhost',
  port: 5447,
  database: 'tw_stats',
  user: 'postgres',
  password: 'password',
});

const s3 = new S3Client({
  endpoint: 'http://localhost:9008',
  region: 'auto',
  forcePathStyle: true,
});

const bucket = 'twstats-archive';
let failed = false;

const idx = await pool.query(
  'SELECT * FROM archive_stream ORDER BY stream_id'
);
console.log(`archive_stream rows: ${idx.rows.length}`);
for (const row of idx.rows) {
  const res = await s3.send(
    new GetObjectCommand({
      Bucket: bucket,
      Key: row.object_key,
      Range: `bytes=${row.byte_offset}-${BigInt(row.byte_offset) + BigInt(row.byte_length) - 1n}`,
    })
  );
  const body = Buffer.concat(await res.Body.toArray());
  const doc = JSON.parse(zlib.gunzipSync(body).toString('utf8'));
  if (doc.stream_id !== row.stream_id) {
    console.error(`MISMATCH: index ${row.stream_id} -> doc ${doc.stream_id}`);
    failed = true;
  }
  console.log(
    `  ${row.stream_id} @ ${row.object_key}[${row.byte_offset}..+${row.byte_length}]`,
    JSON.stringify({
      title: doc.title,
      viewers: doc.viewers,
      titles: doc.titles,
      games: doc.games,
      tags_history: doc.tags_history,
    }, null, 2)
  );
}

const sum = await pool.query('SELECT * FROM stream_summary ORDER BY stream_id');
console.log('stream_summary:');
for (const r of sum.rows) {
  console.log(
    `  ${r.stream_id} user=${r.user_id} dur=${r.duration_seconds}s avg=${r.avg_viewers} peak=${r.peak_viewers} probes=${r.probe_count} games=[${r.game_ids}] titles=${r.title_count}`
  );
}

const hot = await pool.query('SELECT stream_id, user_id, ended_at FROM stream ORDER BY stream_id');
console.log('remaining in hot store:');
for (const r of hot.rows) {
  console.log(`  ${r.stream_id} user=${r.user_id} ended_at=${r.ended_at}`);
}

const archivedStillHot = await pool.query(
  'SELECT s.stream_id FROM stream s JOIN archive_stream a USING (stream_id)'
);
if (archivedStillHot.rows.length > 0) {
  console.error('FAIL: archived streams still in hot store');
  failed = true;
}

await pool.end();
if (failed) process.exit(1);
console.log('verify OK');

